-- =====================================================================-- 0012_helpers.sql-- Schema app: funções de tenant/role/escopo + sync auth.users.-- =====================================================================create schema if not exists app;-- ---------- Identidade e tenant ----------create or replace function app.current_user_id()returns uuid language sql stable as $$  select auth.uid()$$;create or replace function app.current_tenant_id()returns uuidlanguage sql stablesecurity definerset search_path = publicas $$  select tm.tenant_id  from public.tenant_memberships tm  join public.users u on u.id = tm.user_id  where u.auth_user_id = auth.uid()    and tm.status = 'active'  order by tm.created_at asc  limit 1$$;create or replace function app.is_active_member()returns booleanlanguage sql stablesecurity definerset search_path = publicas $$  select exists (    select 1    from public.tenant_memberships tm    join public.users u on u.id = tm.user_id    where u.auth_user_id = auth.uid()      and tm.tenant_id = app.current_tenant_id()      and tm.status = 'active'  )$$;-- ---------- Roles ----------create or replace function app.has_role(roles text[])returns booleanlanguage sql stablesecurity definerset search_path = publicas $$  select exists (    select 1    from public.tenant_memberships tm    join public.users u on u.id = tm.user_id    where u.auth_user_id = auth.uid()      and tm.tenant_id = app.current_tenant_id()      and tm.status = 'active'      and tm.role = any(roles)  )$$;create or replace function app.is_owner()returns boolean language sql stable as $$  select app.has_role(array['owner'])$$;create or replace function app.is_admin_or_owner()returns boolean language sql stable as $$  select app.has_role(array['owner','admin'])$$;-- ---------- Pessoa logada e escopo gerencial ----------create or replace function app.person_id_for_user()returns uuidlanguage sql stablesecurity definerset search_path = publicas $$  select p.id  from public.people p  join public.users u on u.id = p.user_id  where u.auth_user_id = auth.uid()    and p.tenant_id = app.current_tenant_id()  limit 1$$;-- Manager direto (1 nível). v1.1 pode evoluir para recursivo.create or replace function app.manages_person(target_person_id uuid)returns booleanlanguage sql stablesecurity definerset search_path = publicas $$  select exists (    select 1    from public.people p    where p.id = target_person_id      and p.tenant_id = app.current_tenant_id()      and p.manager_person_id = app.person_id_for_user()  )$$;create or replace function app.manager_sees_cycle(p_cycle_id uuid)returns booleanlanguage sql stablesecurity definerset search_path = publicas $$  select exists (    select 1    from public.cycle_participants cp    join public.people p on p.id = cp.person_id    where cp.cycle_id = p_cycle_id      and cp.tenant_id = app.current_tenant_id()      and p.manager_person_id = app.person_id_for_user()  )$$;create or replace function app.report_released(p_cycle_id uuid)returns booleanlanguage sql stablesecurity definerset search_path = publicas $$  select exists (    select 1 from public.cycles c    where c.id = p_cycle_id      and c.tenant_id = app.current_tenant_id()      and c.report_release_at is not null      and c.report_release_at <= now()      and c.status in ('active','closed')  )$$;-- ---------- Sync auth.users -> public.users ----------create or replace function app.tg_sync_auth_user()returns triggerlanguage plpgsqlsecurity definerset search_path = publicas $$begin  insert into public.users (auth_user_id, email, name)  values (    new.id,    new.email,    coalesce(new.raw_user_meta_data->>'name', new.email)  )  on conflict (auth_user_id) do nothing;  return new;end$$;drop trigger if exists on_auth_user_created on auth.users;create trigger on_auth_user_created  after insert on auth.users  for each row execute function app.tg_sync_auth_user();-- Garantir índice único em users.auth_user_id (no-op se já único).create unique index if not exists users_auth_user_id_uniq  on public.users (auth_user_id) where auth_user_id is not null;-- ---------- Anti-escalação de membership ----------create or replace function app.tg_memberships_anti_escalation()returns triggerlanguage plpgsqlsecurity definerset search_path = publicas $$begin  if not app.is_owner() then    if (tg_op = 'UPDATE' and (old.role = 'owner' or new.role = 'owner')) then      raise exception 'only owner can change owner-level memberships';    end if;    if (tg_op = 'DELETE' and old.role = 'owner') then      raise exception 'only owner can delete owner-level memberships';    end if;  end if;  return coalesce(new, old);end$$;drop trigger if exists memberships_anti_escalation on public.tenant_memberships;create trigger memberships_anti_escalation  before update or delete on public.tenant_memberships  for each row execute function app.tg_memberships_anti_escalation();-- ---------- Permissões de execução ----------grant usage on schema app to authenticated, anon;grant execute on function  app.current_user_id(),  app.current_tenant_id(),  app.is_active_member(),  app.has_role(text[]),  app.is_owner(),  app.is_admin_or_owner(),  app.person_id_for_user(),  app.manages_person(uuid),  app.manager_sees_cycle(uuid),  app.report_released(uuid)to authenticated;